import type { Topic } from "./arcadeQuestions";

// ══════════════════════════════════════════════════
// MONGODB — OUTPUT GUESS (💻)
// ══════════════════════════════════════════════════
export const MONGO_OUTPUT_TOPICS: Topic[] = [
  { id:"mongo-out-queries", name:"Output: Queries", icon:"💻", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"What does this query return?\n\ndb.users.find({ age: { $gt: 25 } })",options:["Users with age = 25","Users with age > 25","Users with age >= 25","All users"],answer:"Users with age > 25",explanation:"$gt = greater than. { age: { $gt: 25 } } returns documents where age is strictly greater than 25."},
    {id:2,question:"What does this return?\n\ndb.users.find({ age: { $gte: 18, $lte: 30 } })",options:["age > 18 AND age < 30","age >= 18 AND age <= 30","age >= 18 OR age <= 30","age between 18 and 30 exclusive"],answer:"age >= 18 AND age <= 30",explanation:"$gte = greater than or equal, $lte = less than or equal. Both conditions must be true — implicit AND."},
    {id:3,question:"What does this return?\n\ndb.products.find({ status: { $in: ['active', 'pending'] } })",options:["status = 'active' AND 'pending'","status = 'active' OR status = 'pending'","status NOT in array","Error"],answer:"status = 'active' OR status = 'pending'",explanation:"$in matches if field value equals any value in the array. Works like SQL IN clause."},
    {id:4,question:"How many documents does this return?\n\ndb.users.findOne({ name: 'Ali' })",options:["All matching","0 or many","Exactly 1 or null","Error"],answer:"Exactly 1 or null",explanation:"findOne() returns the first matching document or null if none found — never returns multiple documents."},
    {id:5,question:"What does this query do?\n\ndb.users.find({}, { name: 1, email: 1, _id: 0 })",options:["Returns all fields","Returns only name and email, excludes _id","Returns everything except name and email","Error"],answer:"Returns only name and email, excludes _id",explanation:"Second argument is projection. 1 = include, 0 = exclude. _id: 0 explicitly excludes _id (included by default)."},
    {id:6,question:"What is the result?\n\ndb.users.find({ age: { $not: { $gt: 30 } } })",options:["age > 30","age <= 30 AND null age docs","age = 30","age < 30 only"],answer:"age <= 30 AND null age docs",explanation:"$not negates — returns docs where age is NOT > 30, including docs where age field doesn't exist."},
    {id:7,question:"What does this return?\n\ndb.orders.find().sort({ total: -1 }).limit(5)",options:["5 cheapest orders","5 most expensive orders","All orders sorted","5 random orders"],answer:"5 most expensive orders",explanation:"sort({ total: -1 }) = descending order (highest first). limit(5) = top 5. Combined = 5 highest total orders."},
    {id:8,question:"What does $exists: false return?\n\ndb.users.find({ phone: { $exists: false } })",options:["phone = false","phone = null","Documents where phone field is missing","Documents where phone = undefined"],answer:"Documents where phone field is missing",explanation:"$exists: false finds documents where the field doesn't exist at all (not present in document)."},
    {id:9,question:"What does this count?\n\ndb.users.countDocuments({ status: 'active' })",options:["All documents","Active users count","Inactive users","Error"],answer:"Active users count",explanation:"countDocuments() with filter returns count of documents matching the query — active users only."},
    {id:10,question:"What does skip(10).limit(5) do?\n\ndb.products.find().skip(10).limit(5)",options:["First 15 documents","Documents 1-5","Documents 11-15","Last 5 documents"],answer:"Documents 11-15",explanation:"skip(10) skips first 10. limit(5) returns next 5. Result = documents 11 to 15. Common pagination pattern."},
  ]},
  { id:"mongo-out-crud", name:"Output: CRUD Results", icon:"💻", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"What does insertOne return?\n\ndb.users.insertOne({ name: 'Ali', age: 25 })",options:["The inserted document","{ acknowledged: true, insertedId: ObjectId }","true","null"],answer:"{ acknowledged: true, insertedId: ObjectId }",explanation:"insertOne returns result object with acknowledged:true and insertedId of the new document."},
    {id:2,question:"What happens here?\n\ndb.users.updateOne(\n  { name: 'Ali' },\n  { $set: { age: 26 } }\n)",options:["Replaces whole document","Updates only age field","Creates new document","Deletes then inserts"],answer:"Updates only age field",explanation:"$set updates only specified fields. Other fields remain unchanged. Without $set, whole document would be replaced."},
    {id:3,question:"What does this return?\n\ndb.users.updateMany(\n  { status: 'inactive' },\n  { $set: { archived: true } }\n)",options:["One document","{ acknowledged, matchedCount, modifiedCount }","true","All updated documents"],answer:"{ acknowledged, matchedCount, modifiedCount }",explanation:"updateMany returns result with matchedCount (found) and modifiedCount (actually changed). Not the documents themselves."},
    {id:4,question:"What does $inc do?\n\ndb.products.updateOne(\n  { _id: id },\n  { $inc: { stock: -1 } }\n)",options:["Sets stock to -1","Decrements stock by 1","Deletes stock field","Error for negative"],answer:"Decrements stock by 1",explanation:"$inc increments field by given value. Negative value decrements. stock: -1 reduces stock by 1."},
    {id:5,question:"What does upsert: true do?\n\ndb.users.updateOne(\n  { email: 'x@y.com' },\n  { $set: { name: 'Ali' } },\n  { upsert: true }\n)",options:["Always updates","Inserts if not found, updates if found","Errors if not found","Duplicates document"],answer:"Inserts if not found, updates if found",explanation:"upsert: true = update + insert. If no match found, creates new document. If found, updates it."},
    {id:6,question:"What does $push do?\n\ndb.posts.updateOne(\n  { _id: id },\n  { $push: { tags: 'mongodb' } }\n)",options:["Creates tags array","Adds 'mongodb' to tags array","Replaces tags array","Removes from tags"],answer:"Adds 'mongodb' to tags array",explanation:"$push appends element to array field. If field doesn't exist, creates array with element."},
    {id:7,question:"What does $pull do?\n\ndb.posts.updateOne(\n  { _id: id },\n  { $pull: { tags: 'old' } }\n)",options:["Adds 'old' to tags","Removes all 'old' from tags array","Replaces tags","Creates new array"],answer:"Removes all 'old' from tags array",explanation:"$pull removes all instances of matching value from array. Opposite of $push."},
    {id:8,question:"What does deleteMany({}) do?\n\ndb.logs.deleteMany({})",options:["Deletes collection","Deletes all documents, collection remains","Error — empty filter","Deletes one document"],answer:"Deletes all documents, collection remains",explanation:"Empty filter {} matches all documents. deleteMany({}) deletes all docs but collection structure remains."},
    {id:9,question:"What does $unset do?\n\ndb.users.updateOne(\n  { _id: id },\n  { $unset: { tempField: '' } }\n)",options:["Sets tempField to empty","Sets tempField to null","Removes tempField from document","Error"],answer:"Removes tempField from document",explanation:"$unset removes the specified field from the document entirely. Value '' is ignored — field is deleted."},
    {id:10,question:"What does findOneAndUpdate return by default?\n\ndb.users.findOneAndUpdate(\n  { name: 'Ali' },\n  { $set: { age: 30 } }\n)",options:["Updated document","Original document before update","null","{ acknowledged: true }"],answer:"Original document before update",explanation:"findOneAndUpdate returns original document by default. Add { returnDocument: 'after' } to get updated version."},
  ]},
  { id:"mongo-out-aggregation", name:"Output: Aggregation", icon:"💻", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"What does this aggregate return?\n\ndb.orders.aggregate([\n  { $group: {\n    _id: '$status',\n    count: { $sum: 1 }\n  }}\n])",options:["All orders","Order count per status","Total order count","Error"],answer:"Order count per status",explanation:"$group with _id: '$status' groups by status field. $sum: 1 counts documents per group."},
    {id:2,question:"What does $match early in pipeline do?\n\ndb.orders.aggregate([\n  { $match: { status: 'active' } },\n  { $group: { _id: '$userId', total: { $sum: '$amount' } } }\n])",options:["Groups all orders","Filters first then groups — more efficient","Same as no filter","Error"],answer:"Filters first then groups — more efficient",explanation:"$match early reduces documents before expensive $group. Uses indexes. Best practice: $match as first stage."},
    {id:3,question:"What does $project: { name: 1, _id: 0 } return?\n\ndb.users.aggregate([\n  { $project: { name: 1, _id: 0 } }\n])",options:["All fields","Only name field, no _id","Only _id field","Error"],answer:"Only name field, no _id",explanation:"$project 1 = include, 0 = exclude. Returns documents with only name field, _id explicitly excluded."},
    {id:4,question:"What does $unwind: '$tags' do to this document?\n{ name: 'Post', tags: ['js', 'node'] }",options:["Removes tags","Returns 1 document","Returns 2 documents — one per tag","Error"],answer:"Returns 2 documents — one per tag",explanation:"$unwind deconstructs array. Each array element becomes separate document. 2 tags = 2 output documents."},
    {id:5,question:"What does $lookup return?\n\n{ $lookup: {\n  from: 'orders',\n  localField: '_id',\n  foreignField: 'userId',\n  as: 'userOrders'\n}}",options:["Joins and replaces document","Adds userOrders array with matching orders","Creates new collection","Error if no match"],answer:"Adds userOrders array with matching orders",explanation:"$lookup is left outer join. Adds field (as: 'userOrders') with array of matching documents. Empty array if no match."},
    {id:6,question:"What does $avg calculate?\n\n{ $group: {\n  _id: '$dept',\n  avgSalary: { $avg: '$salary' }\n}}",options:["Total salary","Min salary","Average salary per department","Max salary"],answer:"Average salary per department",explanation:"$avg calculates arithmetic mean of field values per group. avgSalary = sum of salaries / count per department."},
    {id:7,question:"What does $sort: { score: -1 } do?",options:["Sort ascending","Sort descending — highest score first","Random sort","Remove sort"],answer:"Sort descending — highest score first",explanation:"-1 = descending order in $sort. 1 = ascending. { score: -1 } puts highest scores first."},
    {id:8,question:"What does $limit: 10 in pipeline do?",options:["Skips 10","Returns only first 10 documents","Returns last 10","Counts 10"],answer:"Returns only first 10 documents",explanation:"$limit restricts pipeline output to specified count. Combined with $sort, implements top-N queries."},
    {id:9,question:"What does $addFields do?\n\n{ $addFields: {\n  fullName: { $concat: ['$first', ' ', '$last'] }\n}}",options:["Replaces document","Removes first and last","Adds fullName field, keeps existing","Creates new collection"],answer:"Adds fullName field, keeps existing",explanation:"$addFields adds new fields to documents while preserving all existing fields. fullName computed from first + last."},
    {id:10,question:"What does $count return?\n\ndb.users.aggregate([\n  { $match: { active: true } },\n  { $count: 'activeUsers' }\n])",options:["All active users","[{ activeUsers: N }] — single document with count","true","Error"],answer:"[{ activeUsers: N }] — single document with count",explanation:"$count outputs a single document with the specified field containing the count of input documents."},
  ]},
  { id:"mongo-out-indexes", name:"Output: Indexes & Schema", icon:"💻", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"What does explain() show?\n\ndb.users.find({ email: 'a@b.com' }).explain('executionStats')",options:["Query result","Execution plan — IXSCAN or COLLSCAN, time, docs examined","Index list","Error message"],answer:"Execution plan — IXSCAN or COLLSCAN, time, docs examined",explanation:"explain('executionStats') shows how query was executed — whether index was used (IXSCAN) or full scan (COLLSCAN)."},
    {id:2,question:"What does COLLSCAN in explain mean?",options:["Collection created","Index used","Full collection scan — no index — slow for large collections","Collision detected"],answer:"Full collection scan — no index — slow for large collections",explanation:"COLLSCAN = Collection Scan. Every document examined. O(n) — slow. IXSCAN = Index Scan. Much faster."},
    {id:3,question:"What does this index do?\n\ndb.users.createIndex({ email: 1 }, { unique: true })",options:["Speeds up queries only","Ensures no duplicate emails AND speeds queries","Creates email field","Validates email format"],answer:"Ensures no duplicate emails AND speeds queries",explanation:"unique: true prevents duplicate values. Combined with index for fast lookups. Error thrown on duplicate insert."},
    {id:4,question:"What does TTL index do?\n\ndb.sessions.createIndex(\n  { createdAt: 1 },\n  { expireAfterSeconds: 3600 }\n)",options:["Speeds up time queries","Auto-deletes documents 1 hour after createdAt","Archives documents","Creates timestamp"],answer:"Auto-deletes documents 1 hour after createdAt",explanation:"TTL (Time To Live) index automatically removes documents when expireAfterSeconds elapsed. Background process runs periodically."},
    {id:5,question:"What is the result of embedding vs referencing?\n\n// Embedded:\n{ user: { name: 'Ali', address: { city: 'Delhi' } } }\n\n// Referenced:\n{ userId: ObjectId('...') }  // separate collection",options:["Same performance","Embedded: faster reads, data duplication; Referenced: normalized, join needed","Referenced always better","Embedded always better"],answer:"Embedded: faster reads, data duplication; Referenced: normalized, join needed",explanation:"Embed for data accessed together (faster reads, one query). Reference for shared/large/frequently changing data."},
    {id:6,question:"What does getIndexes() return?\n\ndb.users.getIndexes()",options:["Index count","Array of index objects including _id index","Creates indexes","Error"],answer:"Array of index objects including _id index",explanation:"getIndexes() returns array of all indexes on collection. Always includes default _id index plus any custom indexes."},
    {id:7,question:"What does compound index { a:1, b:1 } support?\n\ndb.col.createIndex({ a: 1, b: 1 })",options:["Only { a: 1, b: 1 } queries","Queries on a alone, or a+b together","Queries on b alone only","All possible queries"],answer:"Queries on a alone, or a+b together",explanation:"Compound index supports queries using leftmost prefix. { a } and { a, b } use index. { b } alone cannot use it."},
    {id:8,question:"What does sparse index mean?\n\ndb.users.createIndex({ phone: 1 }, { sparse: true })",options:["Partial index","Only indexes documents where phone field exists","Indexes null values","Faster index"],answer:"Only indexes documents where phone field exists",explanation:"Sparse index excludes documents where indexed field doesn't exist. Smaller index, useful for optional fields."},
    {id:9,question:"What does dropIndex do?\n\ndb.users.dropIndex('email_1')",options:["Drops collection","Removes the email index — queries still work but slower","Drops email field","Error if index used"],answer:"Removes the email index — queries still work but slower",explanation:"dropIndex removes index. Collection and data intact. Queries still work via COLLSCAN — just slower without index."},
    {id:10,question:"What is the output of this schema design?\n\n// One-to-Many: User → Orders\n// orders collection: { userId: ObjectId, total: 100 }\n\ndb.orders.find({ userId: user._id })",options:["Returns user","Returns all orders for that user","Returns user with orders embedded","Error — wrong field"],answer:"Returns all orders for that user",explanation:"Reference pattern: userId in orders references user. Query orders by userId to get all orders for a user."},
  ]},
  { id:"mongo-out-mongoose", name:"Output: Mongoose", icon:"💻", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"What does this Mongoose code return?\n\nconst user = await User.findById(id);\nconsole.log(typeof user);",options:["'object' always","'object' or throws if not found","'object' or null if not found","'undefined'"],answer:"'object' or null if not found",explanation:"findById returns Mongoose document (object) if found, null if not found. Doesn't throw — check for null."},
    {id:2,question:"What does .lean() change?\n\nconst users = await User.find({}).lean();",options:["Makes query faster always","Returns plain JS objects instead of Mongoose documents","Adds lean methods","Removes fields"],answer:"Returns plain JS objects instead of Mongoose documents",explanation:"lean() returns plain JS objects — no Mongoose methods (save, validate). Faster reads. Can't call user.save()."},
    {id:3,question:"What does this Mongoose schema do?\n\nconst schema = new Schema({\n  email: { type: String, unique: true, required: true }\n})",options:["Creates database","Defines structure + validation rules","Inserts document","Creates index only"],answer:"Defines structure + validation rules",explanation:"Schema defines structure (email is String), validation (required), and database hints (unique creates index)."},
    {id:4,question:"What does populate() do?\n\nconst post = await Post\n  .findById(id)\n  .populate('author');",options:["Creates author","Replaces authorId with actual User document","Validates author","Deletes author"],answer:"Replaces authorId with actual User document",explanation:"populate() replaces ObjectId reference with actual document from referenced collection. Like $lookup in aggregation."},
    {id:5,question:"What does pre('save') middleware do?\n\nschema.pre('save', async function() {\n  this.password = await bcrypt.hash(this.password, 10);\n});",options:["Runs after save","Runs before every save — hashes password","Validates password","Runs on find"],answer:"Runs before every save — hashes password",explanation:"pre('save') hook runs before document is saved. Used for hashing passwords, setting timestamps, validation."},
    {id:6,question:"What does this return?\n\nconst count = await User.countDocuments({ active: true });",options:["Array of users","User documents","Number — count of active users","Boolean"],answer:"Number — count of active users",explanation:"countDocuments() returns a number — count of documents matching the filter. Not the documents themselves."},
    {id:7,question:"What does Model.create() do vs new Model().save()?\n\nawait User.create({ name: 'Ali' });\n// vs\nconst u = new User({ name: 'Ali' });\nawait u.save();",options:["Same result","create() skips validation","Both same — create() is shorthand for new+save","save() is faster"],answer:"Both same — create() is shorthand for new+save",explanation:"create() internally does new Model(doc).save(). Both run validation and middleware. create() is more concise."},
    {id:8,question:"What does select('-password') do?\n\nconst user = await User.findById(id).select('-password');",options:["Selects only password","Excludes password from result","Validates password","Hashes password"],answer:"Excludes password from result",explanation:"select('-field') excludes field with - prefix. select('name email') includes only those fields. Like projection."},
    {id:9,question:"What does virtual field return?\n\nschema.virtual('fullName').get(function() {\n  return `${this.firstName} ${this.lastName}`;\n});\nconst user = await User.findById(id);\nconsole.log(user.fullName);",options:["Error — not in DB","'firstName lastName' computed value","null","undefined"],answer:"'firstName lastName' computed value",explanation:"Virtual computes value from other fields. Not stored in DB. Accessed like regular property. Computed on access."},
    {id:10,question:"What does this validation do?\n\nage: {\n  type: Number,\n  min: [0, 'Age must be positive'],\n  max: [150, 'Age too large']\n}",options:["Creates index","Throws at schema definition","Validates before save — error if outside range","JavaScript validation only"],answer:"Validates before save — error if outside range",explanation:"Mongoose validators run before save/create. If age < 0 or > 150, ValidationError thrown with custom message."},
  ]},
];

// ══════════════════════════════════════════════════
// MONGODB — BUG FINDER (🐛)
// ══════════════════════════════════════════════════
export const MONGO_BUG_TOPICS: Topic[] = [
  { id:"mongo-bug-queries", name:"Bug: Queries", icon:"🐛", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\ndb.users.find({ age: 25, age: 30 })",options:["No bug","Duplicate key — second age:30 overwrites first — only age:30 used","Error thrown","Both conditions applied"],answer:"Duplicate key — second age:30 overwrites first — only age:30 used",explanation:"JS object duplicate keys — last wins. Only age:30 used. Use $and: [{ age:25 }, ...] or single condition."},
    {id:2,question:"Find the bug:\n\ndb.users.find({ name: 'Ali' }, { name: 1, age: 0 })",options:["No bug","Cannot mix include (1) and exclude (0) except for _id","Syntax error","Wrong projection"],answer:"Cannot mix include (1) and exclude (0) except for _id",explanation:"Projection can't mix inclusions and exclusions. Only exception: _id can be excluded with inclusions. Fix: use all 1s or all 0s."},
    {id:3,question:"Find the bug:\n\ndb.users.find({ status: 'Active' })\n// No results though 'active' users exist",options:["No bug","Case sensitive — 'Active' != 'active' in MongoDB","Wrong field","find syntax"],answer:"Case sensitive — 'Active' != 'active' in MongoDB",explanation:"MongoDB string comparison is case sensitive. 'Active' and 'active' are different. Use $regex: /^active$/i for case-insensitive."},
    {id:4,question:"Find the bug:\n\nconst id = '507f1f77bcf86cd799439011';\ndb.users.findOne({ _id: id })",options:["No bug","_id must be ObjectId not string — use new ObjectId(id)","Wrong method","find vs findOne"],answer:"_id must be ObjectId not string — use new ObjectId(id)",explanation:"_id is ObjectId type. String won't match. Use: db.users.findOne({ _id: new ObjectId(id) }) or ObjectId(id)."},
    {id:5,question:"Find the bug:\n\ndb.orders.find({\n  $or: { status: 'active', total: { $gt: 100 } }\n})",options:["No bug","$or requires array — { $or: [...] } not object","Wrong operator","Wrong syntax"],answer:"$or requires array — { $or: [...] } not object",explanation:"$or takes array of conditions: { $or: [ { status: 'active' }, { total: { $gt: 100 } } ] }."},
    {id:6,question:"Find the bug:\n\ndb.users.find({ age: null })",options:["No bug","Returns docs where age is null AND docs where age field doesn't exist","Returns null error","Wrong value"],answer:"Returns docs where age is null AND docs where age field doesn't exist",explanation:"{ field: null } matches both null values AND missing fields. Use { age: { $type: 'null' } } for strictly null."},
    {id:7,question:"Find the bug:\n\ndb.users.find().sort({ name: 1 }).limit(10).skip(100)",options:["No bug","skip after limit is inefficient — should be skip before limit, or use range queries","Wrong order","Sort issue"],answer:"No bug",explanation:"MongoDB executes sort → skip → limit regardless of chain order. This is valid and works correctly. No bug."},
    {id:8,question:"Find the bug:\n\ndb.products.find({ tags: { $all: 'javascript' } })",options:["No bug","$all requires array — { $all: ['javascript'] }","Wrong field","Wrong operator"],answer:"$all requires array — { $all: ['javascript'] }",explanation:"$all requires array of values. $all: 'javascript' is wrong. Use: { tags: { $all: ['javascript'] } }."},
    {id:9,question:"Find the bug:\n\ndb.users.find({ $where: 'this.age > 25' })",options:["No bug — valid but slow","$where is deprecated and slow — use regular query operators","Syntax error","Wrong JS"],answer:"No bug — valid but slow",explanation:"$where works but is deprecated in newer MongoDB versions, slow (no index), and security risk. Use { age: { $gt: 25 } } instead."},
    {id:10,question:"Find the bug:\n\ndb.orders.countDocuments()\n// Trying to count all orders",options:["No bug","Missing filter argument — should be countDocuments({})","Wrong method","countDocuments needs filter"],answer:"No bug",explanation:"countDocuments() without argument counts all documents in collection. Empty filter {} is optional. No bug."},
  ]},
  { id:"mongo-bug-updates", name:"Bug: Updates & Schema", icon:"🐛", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\ndb.users.updateOne(\n  { name: 'Ali' },\n  { age: 30 }\n)",options:["No bug","Missing update operator — replaces entire document with { age: 30 }","Wrong filter","Wrong field"],answer:"Missing update operator — replaces entire document with { age: 30 }",explanation:"Without $set, entire document replaced with { age: 30 }. _id preserved but all other fields deleted. Use { $set: { age: 30 } }."},
    {id:2,question:"Find the bug:\n\ndb.users.updateMany(\n  {},\n  { $set: { verified: true } },\n  { upsert: true }\n)",options:["No bug","upsert with empty filter on updateMany — could insert if collection empty","Wrong operator","Missing filter"],answer:"upsert with empty filter on updateMany — could insert if collection empty",explanation:"upsert: true with {} filter: if collection empty, inserts one document. Usually unintended. Avoid upsert with empty filter."},
    {id:3,question:"Find the bug:\n\ndb.posts.updateOne(\n  { _id: id },\n  { $push: { comments: { $each: 'New comment' } } }\n)",options:["No bug","$each requires array — { $each: ['New comment'] }","Wrong operator","Wrong field"],answer:"$each requires array — { $each: ['New comment'] }",explanation:"$each modifier requires array of elements to push. String won't work. Use: { $each: ['New comment'] }."},
    {id:4,question:"Find the bug:\n\ndb.inventory.updateOne(\n  { item: 'apple' },\n  { $inc: { qty: '5' } }\n)",options:["No bug","$inc value must be number not string '5'","Wrong operator","Wrong field"],answer:"$inc value must be number not string '5'",explanation:"$inc requires numeric value. '5' is string — type error. Use: { $inc: { qty: 5 } } with number."},
    {id:5,question:"Find the bug:\n\n// Schema design: storing user activity log\n{\n  userId: ObjectId,\n  activities: [ /* hundreds of entries added daily */ ]\n}",options:["No bug","Unbounded array growth — document will hit 16MB limit","Wrong schema","Missing index"],answer:"Unbounded array growth — document will hit 16MB limit",explanation:"MongoDB documents max 16MB. Unbounded arrays grow forever — will hit limit. Use separate collection or bucket pattern."},
    {id:6,question:"Find the bug:\n\ndb.users.replaceOne(\n  { name: 'Ali' },\n  { $set: { age: 30 } }\n)",options:["No bug","replaceOne doesn't use $set — replaces document with { $set: { age: 30 } } literally","Wrong filter","Wrong method"],answer:"replaceOne doesn't use $set — replaces document with { $set: { age: 30 } } literally",explanation:"replaceOne replaces entire document. Update operators like $set are for updateOne/updateMany. This stores { $set: { age:30 } } literally."},
    {id:7,question:"Find the bug:\n\ndb.users.updateOne(\n  { _id: id },\n  { $rename: { 'oldName': 'name' } }\n)\n// User already has 'name' field",options:["No bug","$rename to existing field — may cause unexpected behavior","Wrong operator","Missing value"],answer:"No bug",explanation:"$rename to existing field name — MongoDB handles this, old field renamed, existing 'name' overwritten. Intentional or not is design question. No error."},
    {id:8,question:"Find the bug:\n\n// Trying to update nested field\ndb.users.updateOne(\n  { _id: id },\n  { $set: { 'address': { city: 'Delhi' } } }\n)\n// User had: address: { city: 'Mumbai', zip: '400001' }",options:["No bug","$set on object replaces entire object — zip field lost","Nested syntax wrong","Wrong operator"],answer:"$set on object replaces entire object — zip field lost",explanation:"$set: { 'address': { city: 'Delhi' } } replaces entire address object. zip field deleted. Use dot notation: { $set: { 'address.city': 'Delhi' } }."},
    {id:9,question:"Find the bug:\n\ndb.products.updateMany(\n  { price: { $lt: 0 } },\n  { $set: { price: 0 } }\n)\n// Trying to fix negative prices",options:["No bug — correct fix","No bug but better to use $max: { price: 0 }","Wrong operator","Wrong filter"],answer:"No bug — correct fix",explanation:"Valid query — finds products with negative prices and sets them to 0. Works correctly. $max alternative also valid but this is fine."},
    {id:10,question:"Find the bug:\n\n// Transaction code\nconst session = client.startSession();\nsession.startTransaction();\ntry {\n  await db.accounts.updateOne({_id: from}, {$inc: {balance: -100}}, {session});\n  await db.accounts.updateOne({_id: to}, {$inc: {balance: 100}}, {session});\n  session.commitTransaction();\n} catch(e) {\n  session.abortTransaction();\n}",options:["No bug","Missing await on commitTransaction and abortTransaction","Wrong session","Wrong operator"],answer:"Missing await on commitTransaction and abortTransaction",explanation:"commitTransaction() and abortTransaction() return Promises — must be awaited. Missing await means transaction may not complete before function returns."},
  ]},
  { id:"mongo-bug-aggregation", name:"Bug: Aggregation", icon:"🐛", difficulty:"Hard", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\ndb.orders.aggregate([\n  { $group: { _id: '$userId', total: { $sum: '$amount' } } },\n  { $match: { status: 'active' } }\n])",options:["No bug","$match after $group can't filter on status — status lost after grouping","Wrong order only","Wrong operator"],answer:"$match after $group can't filter on status — status lost after grouping",explanation:"After $group, only _id and aggregated fields exist. status not in grouped output. Move $match BEFORE $group to filter first."},
    {id:2,question:"Find the bug:\n\ndb.users.aggregate([\n  { $lookup: {\n    from: 'orders',\n    localField: 'id',\n    foreignField: 'userId',\n    as: 'orders'\n  }}\n])",options:["No bug","localField should be '_id' not 'id' — MongoDB uses _id","Wrong from","Wrong as"],answer:"localField should be '_id' not 'id' — MongoDB uses _id",explanation:"MongoDB primary key is _id, not id. localField: '_id' to join with orders.userId correctly."},
    {id:3,question:"Find the bug:\n\ndb.sales.aggregate([\n  { $group: {\n    _id: null,\n    avgPrice: { $avg: 'price' }\n  }}\n])",options:["No bug","Missing $ — should be '$price' not 'price'","Wrong operator","Wrong field"],answer:"Missing $ — should be '$price' not 'price'",explanation:"Field references in aggregation need $ prefix. 'price' is treated as literal string. '$price' references the field value."},
    {id:4,question:"Find the bug:\n\ndb.products.aggregate([\n  { $sort: { price: 1 } },\n  { $limit: 10 },\n  { $skip: 5 }\n])",options:["No bug","Wrong order — skip before limit gives wrong results for pagination","Sort wrong","Limit wrong"],answer:"Wrong order — skip before limit gives wrong results for pagination",explanation:"For pagination: sort → skip → limit. skip after limit: limits to 10 THEN skips 5 = only 5 results. Should be: sort → skip(5) → limit(10)."},
    {id:5,question:"Find the bug:\n\ndb.logs.aggregate([\n  { $match: { date: { $gte: new Date('2024-01-01') } } },\n  { $group: { _id: '$level', count: { $count: {} } } }\n])",options:["No bug","$count is pipeline stage not accumulator — use { $sum: 1 } in $group","Wrong match","Wrong date"],answer:"$count is pipeline stage not accumulator — use { $sum: 1 } in $group",explanation:"$count as accumulator in $group is wrong — it's a pipeline stage. Use { $sum: 1 } to count documents in group."},
    {id:6,question:"Find the bug:\n\ndb.users.aggregate([\n  { $project: {\n    name: 1,\n    age: 1,\n    isAdult: { $gte: ['$age', 18] }\n  }}\n])",options:["No bug — isAdult is boolean","No bug","$gte in $project wrong — need $cond","Syntax error"],answer:"No bug — isAdult is boolean",explanation:"$gte as expression in $project returns boolean true/false. isAdult = true if age >= 18. This is valid. No bug."},
    {id:7,question:"Find the bug:\n\ndb.orders.aggregate([\n  { $unwind: '$items' },\n  { $group: {\n    _id: '$_id',\n    itemCount: { $sum: 1 },\n    totalAmount: { $sum: '$items.price' }\n  }}\n])",options:["No bug","No bug — correct pattern to count items and sum prices","Wrong unwind","Wrong group"],answer:"No bug — correct pattern to count items and sum prices",explanation:"Correct pattern: $unwind creates one doc per item, $group reassembles per order with count and total. No bug."},
    {id:8,question:"Find the bug:\n\ndb.products.aggregate([\n  { $bucket: {\n    groupBy: '$price',\n    boundaries: [0, 50, 100, 500],\n    default: 'Other'\n  }}\n])",options:["No bug","Missing output field — $bucket needs output accumulator","Wrong boundaries","Default wrong"],answer:"Missing output field — $bucket needs output accumulator",explanation:"$bucket requires output field with accumulators: { output: { count: { $sum: 1 } } }. Without output, only _id returned."},
    {id:9,question:"Find the bug:\n\ndb.users.aggregate([\n  { $facet: {\n    byAge: [{ $group: { _id: '$ageGroup' } }],\n    total: { $count: 'totalUsers' }\n  }}\n])",options:["No bug","$facet pipeline values must be arrays — total should be [{ $count: 'totalUsers' }]","Wrong facet","Wrong count"],answer:"$facet pipeline values must be arrays — total should be [{ $count: 'totalUsers' }]",explanation:"Each $facet value must be a pipeline array. total: { $count: ... } is wrong. Use: total: [{ $count: 'totalUsers' }]."},
    {id:10,question:"Find the bug:\n\ndb.orders.aggregate([\n  { $match: { userId: req.params.id } }\n])\n// req.params.id is a string from URL",options:["No bug","userId is ObjectId — string won't match — convert with new ObjectId()","Wrong match","Wrong field"],answer:"userId is ObjectId — string won't match — convert with new ObjectId()",explanation:"URL params are strings. MongoDB ObjectId !== string. Convert: { userId: new ObjectId(req.params.id) }. Always validate first."},
  ]},
  { id:"mongo-bug-mongoose", name:"Bug: Mongoose", icon:"🐛", difficulty:"Hard", category:"Core", questions:[
    {id:1,question:"Find the bug:\n\nconst UserSchema = new Schema({\n  email: String\n});\n\nconst User = mongoose.model('User', UserSchema);\nconst User2 = mongoose.model('User', UserSchema);",options:["No bug","OverwriteModelError — model 'User' already defined","Schema reuse wrong","Two models fine"],answer:"OverwriteModelError — model 'User' already defined",explanation:"Calling model() twice with same name throws OverwriteModelError. Use: mongoose.models.User || mongoose.model('User', UserSchema)."},
    {id:2,question:"Find the bug:\n\nconst user = await User.findById(id);\nuser.name = 'New Name';\nawait User.findByIdAndUpdate(id, { name: 'New Name' });",options:["No bug","Double update — unnecessary findByIdAndUpdate after direct assignment","Missing save","Wrong method"],answer:"Double update — unnecessary findByIdAndUpdate after direct assignment",explanation:"Either modify and user.save() OR use findByIdAndUpdate — not both. This does two DB operations unnecessarily."},
    {id:3,question:"Find the bug:\n\nschema.pre('save', function() {\n  this.updatedAt = new Date();\n});",options:["No bug","Missing async/await or next() — pre hook must call next() or return promise","Wrong this","Wrong hook"],answer:"Missing async/await or next() — pre hook must call next() or return promise",explanation:"Pre hooks need: async function (calls next auto) or call next() explicitly. Without it, save may hang."},
    {id:4,question:"Find the bug:\n\nconst posts = await Post.find({ author: userId })\n  .populate('author')\n  .lean();\nconsole.log(posts[0].author.save());",options:["No bug","lean() returns plain objects — no Mongoose methods like save()","Wrong populate","Wrong find"],answer:"lean() returns plain objects — no Mongoose methods like save()",explanation:"lean() strips Mongoose document methods. author.save() doesn't exist on plain object. Remove lean() or don't call Mongoose methods."},
    {id:5,question:"Find the bug:\n\nconst UserSchema = new Schema({\n  password: String\n});\nUserSchema.methods.toJSON = function() {\n  const obj = this.toObject();\n  return obj; // returning password\n};",options:["No bug","Password exposed in JSON — should delete obj.password before return","Wrong method","toJSON wrong"],answer:"Password exposed in JSON — should delete obj.password before return",explanation:"toJSON called on res.json(user). Returns all fields including password. Add: delete obj.password; return obj; for security."},
    {id:6,question:"Find the bug:\n\nconst results = await User.find({})\n  .populate({\n    path: 'orders',\n    match: { status: 'active' }\n  });\n// Trying to get only users with active orders",options:["No bug — correct filter","populate match filters populated docs but still returns all users","Wrong populate","Wrong match"],answer:"populate match filters populated docs but still returns all users",explanation:"populate match filters the populated array but ALL users returned — just some with empty orders array. Use aggregation $lookup + $match for true filtering."},
    {id:7,question:"Find the bug:\n\nconst schema = new Schema({ name: String });\nschema.index({ name: 1 });\n\nconst Model = mongoose.model('Item', schema);\n// Index never created in DB",options:["No bug","autoIndex: false in production — indexes not auto-created; call Model.ensureIndexes()","Wrong index","Schema issue"],answer:"autoIndex: false in production — indexes not auto-created; call Model.ensureIndexes()",explanation:"Mongoose sets autoIndex:false in production by default. Call Model.ensureIndexes() or createIndexes() manually, or set autoIndex:true in schema options."},
    {id:8,question:"Find the bug:\n\nconst user = new User({ name: 'Ali' });\nawait user.validate();\nawait user.save();",options:["No bug","save() runs validation again — double validation, unnecessary","Wrong order","validate wrong"],answer:"No bug",explanation:"validate() before save() is valid defensive pattern — catch errors early. save() does re-validate but no harm. Some use this to get validation errors before attempting save."},
    {id:9,question:"Find the bug:\n\nUser.find({ age: { $gt: 18 } }, function(err, users) {\n  console.log(users);\n});",options:["No bug","Callback style deprecated in Mongoose 7+ — use async/await or promises","Wrong syntax","Missing error check"],answer:"Callback style deprecated in Mongoose 7+ — use async/await or promises",explanation:"Mongoose 7+ removed callback support. Use: const users = await User.find({ age: { $gt: 18 } }) with async/await."},
    {id:10,question:"Find the bug:\n\nconst schema = new Schema({\n  tags: [String],\n  meta: {\n    views: { type: Number, default: 0 }\n  }\n});\nconst doc = new Model();\nconsole.log(doc.meta.views);",options:["Error — meta undefined","0 — correct, nested default works","undefined","null"],answer:"0 — correct, nested default works",explanation:"Mongoose applies defaults to nested objects. meta.views default is 0. doc.meta.views = 0. No bug — works correctly."},
  ]},
];

// ══════════════════════════════════════════════════
// MONGODB — FILL IN THE BLANK (⬜)
// ══════════════════════════════════════════════════
export const MONGO_FILL_TOPICS: Topic[] = [
  { id:"mongo-fill-queries", name:"Fill: Queries", icon:"⬜", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"Complete to find users older than 25:\n\ndb.users.find({ age: { _____: 25 } })",options:["$gt","$gte","$lt","$eq"],answer:"$gt",explanation:"$gt = greater than. { age: { $gt: 25 } } returns docs where age > 25. $gte for >=."},
    {id:2,question:"Complete to find by multiple values:\n\ndb.products.find({\n  category: { _____: ['electronics', 'clothing'] }\n})",options:["$or","$in","$all","$contains"],answer:"$in",explanation:"$in matches if field value equals any value in array. Like SQL IN clause."},
    {id:3,question:"Complete to exclude password field:\n\ndb.users.find({}, { password: _____ })",options:["false","null","0","'exclude'"],answer:"0",explanation:"Projection: 0 = exclude field. 1 = include field. Cannot mix except _id can be excluded with inclusions."},
    {id:4,question:"Complete to find with AND condition:\n\ndb.orders.find({\n  _____: [\n    { status: 'active' },\n    { total: { $gt: 100 } }\n  ]\n})",options:["$and","$or","$nor","$all"],answer:"$and",explanation:"$and takes array of conditions — all must be true. Implicit AND also works: { status:'active', total:{$gt:100} }."},
    {id:5,question:"Complete to sort descending:\n\ndb.products.find().sort({ price: _____ })",options:["0","-1","'desc'","false"],answer:"-1",explanation:"-1 = descending order (highest first). 1 = ascending. sort({ price: -1 }) = most expensive first."},
    {id:6,question:"Complete to limit results:\n\ndb.users.find().skip(20)._____(10)",options:["limit","take","top","fetch"],answer:"limit",explanation:"limit(n) restricts documents returned. skip(20).limit(10) = page 3 of 10-per-page results."},
    {id:7,question:"Complete to check field exists:\n\ndb.users.find({ phone: { _____: true } })",options:["$has","$exists","$defined","$present"],answer:"$exists",explanation:"$exists: true finds documents where field exists. $exists: false finds documents where field is missing."},
    {id:8,question:"Complete to find one document:\n\nconst user = await db.users._____({ email: 'a@b.com' })",options:["find","findOne","findById","get"],answer:"findOne",explanation:"findOne returns first matching document or null. find returns cursor/array of all matches."},
    {id:9,question:"Complete regex search:\n\ndb.users.find({\n  name: { $regex: /^ali/_____ }\n})",options:["g","i","m","s"],answer:"i",explanation:"/^ali/i — i flag = case-insensitive. Matches 'Ali', 'ALI', 'ali'. $regex: /pattern/flags or $options: 'i'."},
    {id:10,question:"Complete to count documents:\n\nconst total = await db.users._____({})",options:["count","countAll","countDocuments","length"],answer:"countDocuments",explanation:"countDocuments(filter) returns count. {} = all docs. Preferred over deprecated count(). estimatedDocumentCount() for faster approximate count."},
  ]},
  { id:"mongo-fill-crud", name:"Fill: CRUD & Updates", icon:"⬜", difficulty:"Easy", category:"Core", questions:[
    {id:1,question:"Complete to update specific field:\n\ndb.users.updateOne(\n  { _id: id },\n  { _____: { age: 30 } }\n)",options:["$update","$set","$change","update"],answer:"$set",explanation:"$set updates only specified fields. Without operator, replaces entire document. Always use $set for partial updates."},
    {id:2,question:"Complete to increment a field:\n\ndb.products.updateOne(\n  { _id: id },\n  { _____: { views: 1 } }\n)",options:["$add","$increment","$inc","$plus"],answer:"$inc",explanation:"$inc increments field by given value. views: 1 adds 1. views: -1 subtracts 1. Creates field if not exists."},
    {id:3,question:"Complete to insert multiple:\n\ndb.products._____([\n  { name: 'A', price: 10 },\n  { name: 'B', price: 20 }\n])",options:["insertOne","insertMany","insert","addMany"],answer:"insertMany",explanation:"insertMany(array) inserts multiple documents at once. More efficient than multiple insertOne calls."},
    {id:4,question:"Complete to add to array:\n\ndb.posts.updateOne(\n  { _id: id },\n  { _____: { tags: 'mongodb' } }\n)",options:["$add","$append","$push","$insert"],answer:"$push",explanation:"$push appends element to array. $addToSet adds only if not already in array (no duplicates). $pull removes."},
    {id:5,question:"Complete upsert operation:\n\ndb.users.updateOne(\n  { email: 'x@y.com' },\n  { $set: { lastLogin: new Date() } },\n  { _____: true }\n)",options:["insert","create","upsert","merge"],answer:"upsert",explanation:"upsert: true = update if exists, insert if not. Atomic operation — no race condition."},
    {id:6,question:"Complete to remove a field:\n\ndb.users.updateOne(\n  { _id: id },\n  { _____: { tempToken: '' } }\n)",options:["$remove","$delete","$unset","$drop"],answer:"$unset",explanation:"$unset removes field from document. Value '' is ignored. Field completely removed from document."},
    {id:7,question:"Complete to delete one:\n\ndb.logs._____({\n  createdAt: { $lt: new Date('2024-01-01') }\n})",options:["deleteOne","removeOne","drop","erase"],answer:"deleteOne",explanation:"deleteOne removes first matching document. deleteMany removes all matches. drop() removes entire collection."},
    {id:8,question:"Complete findOneAndUpdate to return new doc:\n\nconst updated = await db.users.findOneAndUpdate(\n  { _id: id },\n  { $set: { name: 'Ali' } },\n  { returnDocument: '_____ ' }\n)",options:["new","updated","after","latest"],answer:"after",explanation:"returnDocument: 'after' returns updated document. Default 'before' returns original. returnNewDocument: true is older syntax."},
    {id:9,question:"Complete to push multiple values:\n\ndb.posts.updateOne(\n  { _id: id },\n  { $push: { tags: { _____: ['js', 'node', 'mongo'] } } }\n)",options:["$all","$each","$array","$values"],answer:"$each",explanation:"$each modifier with $push adds multiple values. $push: { tags: { $each: ['a','b'] } } appends all array elements."},
    {id:10,question:"Complete bulk operations:\n\ndb.products._____([\n  { insertOne: { document: { name: 'A' } } },\n  { updateOne: { filter: {_id: id}, update: {$set:{price:10}} } }\n])",options:["bulkWrite","batch","multiWrite","bulkOps"],answer:"bulkWrite",explanation:"bulkWrite executes multiple operations in one request. Mix of insert, update, delete. Efficient for batch operations."},
  ]},
  { id:"mongo-fill-aggregation", name:"Fill: Aggregation", icon:"⬜", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Complete to filter in pipeline:\n\ndb.orders.aggregate([\n  { _____: { status: 'active' } },\n  { $group: { _id: '$userId', total: { $sum: '$amount' } } }\n])",options:["$filter","$find","$match","$where"],answer:"$match",explanation:"$match filters documents in pipeline. Like find() query. Place early to use indexes and reduce documents."},
    {id:2,question:"Complete to group by field:\n\ndb.sales.aggregate([\n  { $group: {\n    _id: '_____category',\n    count: { $sum: 1 }\n  }}\n])",options:["$","#","@","&"],answer:"$",explanation:"$ prefix references field value in aggregation. '$category' means the value of category field. Without $, treated as string literal."},
    {id:3,question:"Complete to calculate average:\n\ndb.orders.aggregate([\n  { $group: {\n    _id: '$dept',\n    avgAmount: { _____: '$amount' }\n  }}\n])",options:["$mean","$average","$avg","$arithmetic"],answer:"$avg",explanation:"$avg calculates arithmetic mean. Use in $group with field reference. $sum, $min, $max, $avg are common accumulators."},
    {id:4,question:"Complete the $lookup join:\n\n{ $lookup: {\n  from: '_____',\n  localField: 'userId',\n  foreignField: '_id',\n  as: 'userInfo'\n}}",options:["userId","user","users","UserModel"],answer:"users",explanation:"from: 'users' specifies collection to join. MongoDB collection names typically lowercase plural. Matches documents by userId = _id."},
    {id:5,question:"Complete to flatten array:\n\ndb.posts.aggregate([\n  { _____: '$tags' },\n  { $group: { _id: '$tags', count: { $sum: 1 } } }\n])",options:["$flatten","$spread","$unwind","$expand"],answer:"$unwind",explanation:"$unwind deconstructs array field — creates one document per array element. Then group to count tag occurrences."},
    {id:6,question:"Complete to add computed field:\n\ndb.products.aggregate([\n  { _____: {\n    totalValue: { $multiply: ['$price', '$quantity'] }\n  }}\n])",options:["$project","$compute","$addFields","$set"],answer:"$addFields",explanation:"$addFields adds new fields while preserving existing ones. $project can also add fields but must explicitly include others."},
    {id:7,question:"Complete to get first N per group:\n\ndb.orders.aggregate([\n  { $sort: { amount: -1 } },\n  { $group: {\n    _id: '$userId',\n    topOrder: { _____: '$amount' }\n  }}\n])",options:["$first","$max","$top","$head"],answer:"$first",explanation:"$first accumulator returns first value in group. After sorting by amount desc, $first gets highest amount per user."},
    {id:8,question:"Complete to count in pipeline:\n\ndb.users.aggregate([\n  { $match: { active: true } },\n  { _____: 'activeCount' }\n])",options:["$size","$count","$total","$length"],answer:"$count",explanation:"$count stage outputs single document with count. 'activeCount' is the field name for the count value."},
    {id:9,question:"Complete to limit pipeline results:\n\ndb.products.aggregate([\n  { $sort: { rating: -1 } },\n  { _____: 10 }\n])",options:["$limit","$top","$take","$first"],answer:"$limit",explanation:"$limit in aggregation pipeline restricts output documents. Combined with $sort implements top-N queries."},
    {id:10,question:"Complete to reshape document:\n\ndb.users.aggregate([\n  { _____: {\n    fullName: { $concat: ['$firstName', ' ', '$lastName'] },\n    _id: 0\n  }}\n])",options:["$reshape","$addFields","$project","$transform"],answer:"$project",explanation:"$project selects, renames, and computes fields. 1=include, 0=exclude. Computed fields use expressions like $concat."},
  ]},
  { id:"mongo-fill-mongoose", name:"Fill: Mongoose", icon:"⬜", difficulty:"Medium", category:"Core", questions:[
    {id:1,question:"Complete Mongoose connection:\n\nawait mongoose._____(process.env.MONGO_URI);",options:["open","link","connect","init"],answer:"connect",explanation:"mongoose.connect(uri) establishes connection. Returns Promise. Use await or .then(). Set options like { useNewUrlParser: true }."},
    {id:2,question:"Complete schema definition:\n\nconst userSchema = new mongoose._____({\n  name: { type: String, required: true },\n  age: Number\n});",options:["Model","Document","Schema","Blueprint"],answer:"Schema",explanation:"new mongoose.Schema({}) defines document structure. Then mongoose.model('User', userSchema) creates Model."},
    {id:3,question:"Complete to make field required:\n\nconst schema = new Schema({\n  email: {\n    type: String,\n    _____: true,\n    unique: true\n  }\n});",options:["mandatory","needed","required","notNull"],answer:"required",explanation:"required: true means field must be provided. Mongoose throws ValidationError if missing on save."},
    {id:4,question:"Complete to add instance method:\n\nuserSchema._____.comparePassword = async function(candidate) {\n  return bcrypt.compare(candidate, this.password);\n};",options:["statics","virtuals","methods","prototype"],answer:"methods",explanation:"schema.methods adds instance methods — called on document instances. schema.statics adds class methods called on Model."},
    {id:5,question:"Complete to add static method:\n\nuserSchema._____.findByEmail = function(email) {\n  return this.findOne({ email });\n};",options:["methods","virtuals","statics","helpers"],answer:"statics",explanation:"schema.statics adds static methods — called on Model directly: User.findByEmail('x'). schema.methods for instances."},
    {id:6,question:"Complete populate:\n\nconst post = await Post.findById(id)\n  ._____({\n    path: 'author',\n    select: 'name email'\n  });",options:["join","lookup","populate","include"],answer:"populate",explanation:"populate() replaces ObjectId reference with actual document. path: field to populate, select: fields to return."},
    {id:7,question:"Complete virtual:\n\nuserSchema.virtual('fullName')\n  ._____(function() {\n    return `${this.firstName} ${this.lastName}`;\n  });",options:["value","compute","get","define"],answer:"get",explanation:"virtual('name').get(fn) defines getter — computed when accessed. .set(fn) defines setter. Not stored in DB."},
    {id:8,question:"Complete pre-save hook:\n\nuserSchema.___('save', async function(next) {\n  if (this.isModified('password')) {\n    this.password = await bcrypt.hash(this.password, 10);\n  }\n  next();\n});",options:["hook","middleware","pre","on"],answer:"pre",explanation:"pre('save', fn) runs before save. post('save', fn) runs after. Call next() to continue or pass error to next(err)."},
    {id:9,question:"Complete lean query:\n\nconst users = await User.find({})._____()\nconsole.log(users[0] instanceof User); // false",options:["plain","raw","lean","simple"],answer:"lean",explanation:"lean() returns plain JS objects instead of Mongoose documents. Faster — no Mongoose overhead. instanceof User = false."},
    {id:10,question:"Complete to exclude field from all queries:\n\nconst schema = new Schema({\n  password: { type: String, _____: false }\n});",options:["hidden","private","select","exclude"],answer:"select",explanation:"select: false excludes field from query results by default. Use .select('+password') to explicitly include when needed."},
  ]},
];